    "name": "database-cloud-optimization-database-architect",
    "title": "database-cloud-optimization-database-architect",
    "description": "Expert database architect specializing in data layer design from scratch, technology selection, schema modeling, and scalable database architectures. Masters SQL/NoSQL/TimeSeries database selection…",
    "source": "https://raw.githubusercontent.com/wshobson/agents/main/plugins/database-cloud-optimization/agents/database-architect.md",
